toolArgs.old_str:
    // Relay class so DotNetObjectReference doesn't require the open generic component
    public sealed class CallbackRelay
    {
        private readonly InfiniteScrollList<TItem> _owner;

        internal CallbackRelay(InfiniteScrollList<TItem> owner) => _owner = owner;

        [JSInvokable("OnSentinelVisible")]
        public async Task OnSentinelVisible()
        {
            await _owner.InvokeAsync(async () =>
            {
                await _owner.HandleSentinelVisible();
            });
        }
    }
}

